1	export type Cell = [number, number];
2	
3	function isNeighbor(cell: Cell, other: Cell): boolean {
4	  const sameCell = other[0] === cell[0] && other[1] === cell[1];
5	  return (
6	    !sameCell &&
7	    Math.abs(other[0] - cell[0]) <= 1 &&
8	    Math.abs(other[1] - cell[1]) <= 1
9	  );
10	}
11	
12	function countNeighbors(cell: Cell, cells: Cell[]): number {
13	  return cells.filter((other) => isNeighbor(cell, other)).length;
14	}
15	
16	function isLive(cell: Cell, cells: Cell[]): boolean {
17	  return cells.some(
18	    (other) => other[0] === cell[0] && other[1] === cell[1],
19	  );
20	}
21	
22	function deadNeighborCandidates(cells: Cell[]): Cell[] {
23	  const offsets = [-1, 0, 1];
24	  const candidates: Cell[] = [];
25	  for (const cell of cells) {
26	    for (const dx of offsets) {
27	      for (const dy of offsets) {
28	        const candidate: Cell = [cell[0] + dx, cell[1] + dy];
29	        if (isLive(candidate, cells)) continue;
30	        if (isLive(candidate, candidates)) continue;
31	        candidates.push(candidate);
32	      }
33	    }
34	  }
35	  return candidates;
36	}
37	
38	export function nextGeneration(cells: Cell[]): Cell[] {
39	  const survivors = cells.filter((cell) => {
40	    const neighborCount = countNeighbors(cell, cells);
41	    return neighborCount === 2 || neighborCount === 3;
42	  });
43	
44	  const births = deadNeighborCandidates(cells).filter(
45	    (candidate) => countNeighbors(candidate, cells) === 3,
46	  );
47	
48	  return [...survivors, ...births];
49	}
